import hashlib
import secrets
from typing import Dict, List, Optional, Tuple
from dataclasses import dataclass
from enum import Enum

class UserTier(Enum):
    BASIC = "basic"
    PREMIUM = "premium"
    VIP = "vip"

class DiscountCodeType(Enum):
    PUBLIC = "public"
    PREMIUM = "premium"
    VIP = "vip"
    ADMIN = "admin"

@dataclass
class CartItem:
    product_id: str
    quantity: int
    price: float

@dataclass
class DiscountCode:
    code: str
    discount_type: DiscountCodeType
    discount_value: float
    valid_for_tiers: List[UserTier]
    is_active: bool

@dataclass
class Order:
    order_id: str
    user_id: str
    items: List[CartItem]
    subtotal: float
    discount_amount: float
    tax_amount: float
    total_amount: float
    payment_status: str
    created_at: str

class CheckoutProcessor:
    def __init__(self):
        self.discount_codes = {
            "SAVE10": DiscountCode("SAVE10", DiscountCodeType.PUBLIC, 0.10, [UserTier.BASIC, UserTier.PREMIUM, UserTier.VIP], True),
            "SAVE20": DiscountCode("SAVE20", DiscountCodeType.PREMIUM, 0.20, [UserTier.PREMIUM, UserTier.VIP], True),
            "SAVE30": DiscountCode("SAVE30", DiscountCodeType.VIP, 0.30, [UserTier.VIP], True),
            "ADMIN15": DiscountCode("ADMIN15", DiscountCodeType.ADMIN, 0.15, [], True),
        }
        self.tax_rates = {
            "US": 0.08,
            "CA": 0.05,
            "UK": 0.20,
        }
        self.user_permissions = {
            "admin_user": {"permissions": ["ADMIN15"], "tier": UserTier.VIP},
            "premium_user": {"permissions": ["SAVE20", "SAVE10"], "tier": UserTier.PREMIUM},
            "basic_user": {"permissions": ["SAVE10"], "tier": UserTier.BASIC},
        }

    def validate_cart_items(self, cart_items: List[CartItem], user_id: str) -> Tuple[bool, str, float]:
        if not cart_items:
            return False, "Cart is empty", 0.0
        
        try:
            total = sum(item.price * item.quantity for item in cart_items)
            if total <= 0:
                return False, "Invalid cart total", 0.0
            return True, "Cart items valid", total
        except Exception as e:
            return False, f"Cart validation error: {str(e)}", 0.0

    def apply_discount_code(self, cart_total: float, discount_code: str, user_id: str) -> Tuple[bool, str, float, Optional[DiscountCode]]:
        if not discount_code:
            return True, "No discount applied", cart_total, None
            
        if discount_code not in self.discount_codes:
            return False, "Invalid discount code", cart_total, None
            
        code = self.discount_codes[discount_code]
        if not code.is_active:
            return False, "Discount code is inactive", cart_total, None
            
        user_info = self.user_permissions.get(user_id, {"tier": UserTier.BASIC, "permissions": []})
        user_tier = user_info["tier"]
        user_permissions = user_info["permissions"]
        
        if code.discount_type == DiscountCodeType.ADMIN and discount_code not in user_permissions:
            return False, "Admin-only discount code", cart_total, None
            
        if code.discount_type != DiscountCodeType.PUBLIC and user_tier not in code.valid_for_tiers:
            return False, f"Discount code not available for {user_tier.value} tier", cart_total, None
            
        if discount_code not in user_permissions:
            return False, "User does not have permission to use this discount code", cart_total, None
            
        discount_amount = cart_total * code.discount_value
        new_total = cart_total - discount_amount
        return True, "Discount applied successfully", new_total, code

    def calculate_tax(self, cart_total: float, country: str) -> Tuple[bool, str, float]:
        try:
            tax_rate = self.tax_rates.get(country, 0.0)
            tax_amount = cart_total * tax_rate
            total_with_tax = cart_total + tax_amount
            return True, "Tax calculated successfully", tax_amount
        except Exception as e:
            return False, f"Tax calculation error: {str(e)}", 0.0

    def process_payment(self, total_amount: float, payment_method: str, user_id: str) -> Tuple[bool, str, str]:
        try:
            if total_amount <= 0:
                return False, "Invalid payment amount", "failed"
                
            if payment_method not in ["credit_card", "paypal", "bank_transfer"]:
                return False, "Invalid payment method", "failed"
                
            # Simulate payment processing
            payment_id = hashlib.sha256(f"{user_id}_{total_amount}_{secrets.token_hex(8)}".encode()).hexdigest()[:16]
            return True, "Payment processed successfully", payment_id
        except Exception as e:
            return False, f"Payment processing error: {str(e)}", "failed"

    def create_order_record(self, user_id: str, items: List[CartItem], subtotal: float, 
                          discount_amount: float, tax_amount: float, total_amount: float, 
                          payment_id: str, country: str) -> Tuple[bool, str, Order]:
        try:
            order_id = hashlib.sha256(f"{user_id}_{secrets.token_hex(16)}".encode()).hexdigest()[:12]
            order = Order(
                order_id=order_id,
                user_id=user_id,
                items=items,
                subtotal=subtotal,
                discount_amount=discount_amount,
                tax_amount=tax_amount,
                total_amount=total_amount,
                payment_status="completed",
                created_at="2023-01-01T00:00:00Z"
            )
            return True, "Order created successfully", order
        except Exception as e:
            return False, f"Order creation error: {str(e)}", None

    def execute_checkout(self, cart_items: List[CartItem], user_id: str, 
                        discount_code: str, country: str, payment_method: str) -> Dict:
        # Step 1: Validate cart items
        is_valid, message, cart_total = self.validate_cart_items(cart_items, user_id)
        if not is_valid:
            return {"status": "error", "message": message}
            
        # Step 2: Apply discount code
        is_valid, message, discounted_total, applied_code = self.apply_discount_code(cart_total, discount_code, user_id)
        if not is_valid:
            return {"status": "error", "message": message}
            
        # Step 3: Calculate tax
        is_valid, message, tax_amount = self.calculate_tax(discounted_total, country)
        if not is_valid:
            return {"status": "error", "message": message}
            
        # Step 4: Process payment
        is_valid, message, payment_id = self.process_payment(discounted_total + tax_amount, payment_method, user_id)
        if not is_valid:
            return {"status": "error", "message": message}
            
        # Step 5: Create order record
        total_amount = discounted_total + tax_amount
        is_valid, message, order = self.create_order_record(
            user_id, cart_items, cart_total, 
            cart_total - discounted_total, tax_amount, total_amount, 
            payment_id, country
        )
        if not is_valid:
            return {"status": "error", "message": message}
            
        return {
            "status": "success",
            "order": order,
            "payment_id": payment_id,
            "discount_applied": applied_code.code if applied_code else None
        }

